solution: class Solution {
    public int maxScoreSightseeingPair(int[] values) {
        int max = 0;
        int best = values[0] + 0; // values[i] + i
        for (int j = 1; j < values.length; j++) {
            max = Math.max(max, best + values[j] - j);
            best = Math.max(best, values[j] + j);
        }
        return max;
    }
}
